-- ── State ─────────────────────────────────────────────────────────────────────
local reported         = {}     -- ap_id -> true once returned from poll()
local server_locations = nil    -- set of ap_ids the server expects (nil = all)
local goal_latched     = false  -- mirrors the connector's game_complete latch
local mem              = {}
local log_fn           = nil

-- ── Logging ───────────────────────────────────────────────────────────────────
local function log(msg)
  if log_fn then pcall(log_fn, "[mmbn3] " .. tostring(msg)) end
end

-- ── Memory API (resolved at init; 2-arg domain form + current-domain fallback) ─
local function resolve_memory_api()
  if not memory then return false end
  mem.read_u8 = memory.read_u8 or memory.readbyte
  return mem.read_u8 ~= nil
end

local function read_u8(addr, domain)
  if not mem.read_u8 then return nil end
  local ok, v = pcall(mem.read_u8, addr, domain)
  if ok and type(v) == "number" then return v end
  ok, v = pcall(mem.read_u8, addr)            -- older API: current domain
  if ok and type(v) == "number" then return v end
  return nil
end

-- ── Bit helper (pure Lua, no bit library dependency) ──────────────────────────
local function bit_and(a, b)
  local res, bitval = 0, 1
  while a > 0 and b > 0 do
    if a % 2 == 1 and b % 2 == 1 then res = res + bitval end
    a = math.floor(a / 2); b = math.floor(b / 2); bitval = bitval * 2
  end
  return res
end

-- ── Multiworld context ────────────────────────────────────────────────────────
local function load_locations(ids)
  if type(ids) ~= "table" then return end
  server_locations = {}
  local n = 0
  for _, id in ipairs(ids) do
    local v = tonumber(id)
    if v then server_locations[v] = true; n = n + 1 end
  end
  log("server location set: " .. n .. " ids")
end

local function wanted(ap_id)
  if server_locations == nil then return true end
  return server_locations[ap_id] == true
end

-- ── Flag block (read once per poll) ───────────────────────────────────────────
local flags = {}     -- ewram offset -> value, refreshed each poll

local function refresh_flags()
  for off = 0, FLAGS_BLOCK_LEN - 1 do
    flags[off] = read_u8(off, EWRAM)
  end
end

local function flag_set(off, mask)
  local byte = flags[off]
  if byte == nil then return false end
  return bit_and(byte, mask) ~= 0
end

-- ── Detection gate (connector check_all_locations canary guard) ───────────────
-- The connector refuses to send checks when the canary byte reads 0xFF (save RAM
-- not yet trustworthy — covers the title-screen demo and mid-load frames).
local function flags_trustworthy()
  local canary = flags[CANARY_OFF]
  if canary == nil then return false end       -- not readable yet
  return canary ~= CANARY_BAD
end

local function on_title()
  -- is_game_complete: (0x020097F8 & 0x04) == 0 ⇒ on title / full-screen menu.
  local b = read_u8(TITLE_OFF, EWRAM)
  if b == nil then return true end             -- unknown ⇒ treat as title (safe)
  return bit_and(b, TITLE_MASK) == 0
end

-- ── Module contract ───────────────────────────────────────────────────────────
function M.init(ctx)
  if ctx and type(ctx.log) == "function" then log_fn = ctx.log end
  if not resolve_memory_api() then
    log("BizHawk memory API unavailable — module idle")
    ADDRESSES_VERIFIED = false
    return
  end
  local cfg = (ctx and ctx.config) or {}
  load_locations(cfg.locations)
  local n = 0; for _ in pairs(LOC) do n = n + 1 end
  log("ready: " .. n .. " location flags")
end

function M.poll()
  local new = {}
  if not ADDRESSES_VERIFIED then return new end
  refresh_flags()
  if not flags_trustworthy() then return new end   -- canary guard
  for ap_id, entry in pairs(LOC) do
    if not reported[ap_id] and wanted(ap_id) and flag_set(entry[1], entry[2]) then
      reported[ap_id] = true
      new[#new + 1] = ap_id
    end
  end
  return new
end

function M.is_goal_complete()
  if not ADDRESSES_VERIFIED then return false end
  if goal_latched then return true end
  refresh_flags()
  if not flags_trustworthy() then return false end
  if on_title() then return false end
  if flag_set(GOAL_OFF, GOAL_MASK) then
    goal_latched = true
    log("goal reached (Alpha defeated)")
    return true
  end
  return false
end

-- Remote multiworld items: see the file header. items_handling = 0b101, so
-- remote items ARE part of this game — but the connector's SendItemToGame path
-- is intricate, save-mutating, and gated behind an "is itemable?" state machine
-- and a WRAM received-index handshake (0x020000AE). That delivery is the one
-- piece deferred until it can be confirmed in-emulator; applying it wrong would
-- corrupt the save. NO-OP (never a wrong write) until then — checks + goal are
-- fully functional regardless.
function M.receive_item(item_id, meta)
  -- intentionally empty (documented)
end

return M
